const user = $('Loop por usuário').item.json;
const txs = $input.all().map(i => i.json).filter(t => t && t.type);
const receita = txs.filter(t => t.type === 'receita').reduce((s, t) => s + parseFloat(t.amount || 0), 0);
const despesa = txs.filter(t => t.type === 'despesa').reduce((s, t) => s + parseFloat(t.amount || 0), 0);
const liquido = receita - despesa;
const meta = parseFloat(user.monthly_goal || 0);
const progressoMeta = meta > 0 ? Math.round((receita / meta) * 100) : 0;
const margemPct = receita > 0 ? Math.round((liquido / receita) * 100) : 0;

// Classificar a semana
let classificacao;
if (meta > 0) {
  const metaSemanal = meta / 4;
  const pctMetaSemanal = receita / metaSemanal * 100;
  if (pctMetaSemanal >= 120 && margemPct >= 70) classificacao = 'EXCELENTE';
  else if (pctMetaSemanal >= 80 && margemPct >= 50) classificacao = 'BOA';
  else if (pctMetaSemanal >= 40) classificacao = 'REGULAR';
  else classificacao = 'FRACA';
} else {
  if (receita > 0 && margemPct >= 80) classificacao = 'BOA';
  else if (receita > 0) classificacao = 'REGULAR';
  else classificacao = 'FRACA';
}

const hoje = new Date();
const semanaInicio = new Date(hoje - 7*86400000).toLocaleDateString('pt-BR', {day:'2-digit',month:'2-digit'});
const semanaFim = hoje.toLocaleDateString('pt-BR', {day:'2-digit',month:'2-digit'});

const firstName = (user.name || 'Amigo').split(' ')[0];

return [{ json: { userId: user.id, userName: user.name, firstName, userPhone: user.phone, receita: receita.toFixed(2), despesa: despesa.toFixed(2), liquido: liquido.toFixed(2), meta: meta.toFixed(2), progressoMeta, margemPct, totalTx: txs.length, semanaInicio, semanaFim, classificacao } }];

const texto = $input.first().json.choices[0].message.content;
const dados = $('Calcular resumo').item.json;
return [{ json: { ...dados, texto } }];
